            .map(|v| v["path"].as_str().unwrap().to_string())
            .collect();
        assert!(linked.contains(&"references/api.md".to_string()));
        assert!(linked.contains(&"templates/prompt.txt".to_string()));
        assert!(linked.contains(&"scripts/run.sh".to_string()));
